import { createWebHashHistory } from "vue-router";
import {  createRouter } from "vue-router";
import Home from '../views/Home.vue'



const routes = [
  {
    path: '/',
    name: 'Home',
    component: Home
  },
]

const router = createRouter({
    history: createWebHashHistory(),
    routes,
  });
  
  export default router;
